package arch.day3;

/**
 * Day 3 basic: operator truth tables and control keywords as static output.
 * // Maps assignment themes: short-circuit, break/continue, return style guards.
 */
public class Day3Basic {

    static void row(String name, String meaning) {
        System.out.println(name + " | " + meaning);
    }

    static void band(String label, int lo, int hi, int sample) {
        boolean inBand = sample >= lo && sample <= hi;
        System.out.println(label + "[" + lo + "," + hi + "] contains " + sample + " -> " + inBand);
    }

    public static void main(String[] args) {
        System.out.println("=== Relational samples (int) ===");
        row("5 > 3", String.valueOf(5 > 3));
        row("5 == 5", String.valueOf(5 == 5));
        row("5 != 3", String.valueOf(5 != 3));
        row("7 <= 7", String.valueOf(7 <= 7));
        System.out.println();

        System.out.println("=== Logical short-circuit truth ===");
        row("false && true", "right skipped -> false");
        row("true || false", "right skipped -> true");
        row("true && false", "both evaluated -> false");
        System.out.println();

        System.out.println("=== Loop control keywords ===");
        System.out.println("break    | exit innermost loop or switch");
        System.out.println("continue | jump to next loop iteration");
        System.out.println("return   | exit current method with optional value");
        System.out.println();

        System.out.println("=== Guard pattern (early return) ===");
        System.out.println("if (n < 0) return \"bad\";");
        System.out.println("// avoids else pyramid for happy path readers");
        System.out.println();

        System.out.println("=== FizzBuzz ordering rule ===");
        System.out.println("check divisible-by-15 before 3-only and 5-only branches");
        System.out.println();

        System.out.println("=== Sample range checks (static ints) ===");
        band("tierA", 0, 10, 5);
        band("tierB", 11, 20, 5);
        band("tierC", 21, 30, 25);
        System.out.println();

        System.out.println("=== Ternary readability ===");
        int score = 82;
        String bucket = score >= 80 ? "pass" : "review";
        System.out.println("score " + score + " -> " + bucket);
    }
}

package arch.day3;

/**
 * Day 3 intermediate: four labelled scenarios for operators and control flow.
 */
public class Day3Intermediate {

    static void scenario1() {
        System.out.println("--- Scenario 1: short-circuit avoids divide-by-zero ---");
        int x = 0;
        boolean ok = (x != 0) && (10 / x > 1);
        System.out.println("x=0 predicate result: " + ok + " (no exception)");
        System.out.println();
    }

    static void scenario2() {
        System.out.println("--- Scenario 2: break vs continue in one loop ---");
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 8; i++) {
            if (i % 2 == 0) {
                continue;
            }
            sb.append(i);
            if (i >= 5) {
                break;
            }
        }
        System.out.println("odd digits collected before break: " + sb);
        System.out.println();
    }

    static void scenario3() {
        System.out.println("--- Scenario 3: double if FizzBuzz bug at 15 ---");
        int i = 15;
        StringBuilder lines = new StringBuilder();
        if (i % 3 == 0) {
            lines.append("Fizz\n");
        }
        if (i % 5 == 0) {
            lines.append("Buzz\n");
        }
        if (i % 3 != 0 && i % 5 != 0) {
            lines.append(i).append("\n");
        }
        System.out.print(lines);
        System.out.println("(symptom: two lines instead of one FizzBuzz)");
        System.out.println();
    }

    static void scenario4() {
        System.out.println("--- Scenario 4: else-if fix preserves single output ---");
        int i = 15;
        if (i % 15 == 0) {
            System.out.println("FizzBuzz");
        } else if (i % 3 == 0) {
            System.out.println("Fizz");
        } else if (i % 5 == 0) {
            System.out.println("Buzz");
        } else {
            System.out.println(i);
        }
        System.out.println();
    }

    public static void main(String[] args) {
        scenario1();
        scenario2();
        scenario3();
        scenario4();
    }
}

package arch.day3;

import java.util.LinkedHashMap;
import java.util.Map;

/**
 * Day 3 advanced: trial division primality + decision table (deterministic).
 */
public class Day3Advanced {

    static boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        if (n == 2) {
            return true;
        }
        if (n % 2 == 0) {
            return false;
        }
        int limit = (int) Math.sqrt(n);
        for (int d = 3; d <= limit; d += 2) {
            if (n % d == 0) {
                return false;
            }
        }
        return true;
    }

    static String classifyLoop(int n) {
        if (n < 0) {
            return "invalid";
        }
        if (n == 0) {
            return "zero-trip-for";
        }
        if (n == 1) {
            return "single-trip-while";
        }
        return "multi-trip-for";
    }

    static int countDivisors(int n) {
        if (n <= 0) {
            return 0;
        }
        int c = 0;
        int lim = (int) Math.sqrt(n);
        for (int d = 1; d <= lim; d++) {
            if (n % d != 0) {
                continue;
            }
            int other = n / d;
            c++;
            if (other != d) {
                c++;
            }
        }
        return c;
    }

    static String fizzBuzzLine(int i) {
        if (i % 15 == 0) {
            return "FizzBuzz";
        }
        if (i % 3 == 0) {
            return "Fizz";
        }
        if (i % 5 == 0) {
            return "Buzz";
        }
        return String.valueOf(i);
    }

    public static void main(String[] args) {
        System.out.println("=== Block 1: primes 1..50 ===");
        StringBuilder primes = new StringBuilder();
        for (int v = 2; v <= 50; v++) {
            if (isPrime(v)) {
                if (primes.length() > 0) {
                    primes.append(' ');
                }
                primes.append(v);
            }
        }
        System.out.println(primes);
        System.out.println();

        System.out.println("=== Block 2: loop shape classifier ===");
        int[] samples = {-1, 0, 1, 5};
        for (int s : samples) {
            System.out.println("n=" + s + " -> " + classifyLoop(s));
        }
        System.out.println();

        System.out.println("--- Extra: divisor count for sample composites ---");
        int[] comps = {12, 17, 28};
        for (int c : comps) {
            System.out.println("divisors(" + c + ")=" + countDivisors(c));
        }
        System.out.println();

        System.out.println("--- Extra: FizzBuzz line for 1..18 sample ---");
        StringBuilder fb = new StringBuilder();
        for (int i = 1; i <= 18; i++) {
            if (fb.length() > 0) {
                fb.append(',');
            }
            fb.append(fizzBuzzLine(i));
        }
        System.out.println(fb);
        System.out.println();

        System.out.println("=== Block 3: branch review matrix ===");
        Map<String, String> table = new LinkedHashMap<>();
        table.put("double independent if", "may fire twice; use else-if for exclusivity");
        table.put("while(true) without break", "risk non-termination; prove progress");
        table.put("continue before cleanup", "resource leak risk; audit finally placement");
        table.put("nested ternary", "hard review; flatten with returns");
        for (Map.Entry<String, String> e : table.entrySet()) {
            System.out.println(e.getKey() + " -> " + e.getValue());
        }
    }
}

