package arch.day3;

public class Day3Exercise {

    static boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        if (n == 2) {
            return true;
        }
        if (n % 2 == 0) {
            return false;
        }
        int limit = (int) Math.sqrt(n);
        for (int d = 3; d <= limit; d += 2) {
            if (n % d == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        int x = 0;
        boolean sc = (x != 0) && (10 / x > 1);
        System.out.println("shortCircuit x=0 -> " + sc);

        StringBuilder odds = new StringBuilder("oddIndices: ");
        int appended = 0;
        for (int i = 0; i < 20; i++) {
            if (i % 2 == 0) {
                continue;
            }
            odds.append(i).append(' ');
            appended++;
            if (appended == 3) {
                break;
            }
        }
        System.out.println(odds.toString().trim());

        int bug = 15;
        System.out.println("bug15:");
        if (bug % 3 == 0) {
            System.out.println("Fizz");
        }
        if (bug % 5 == 0) {
            System.out.println("Buzz");
        }
        System.out.println("fix15:");
        if (bug % 15 == 0) {
            System.out.println("FizzBuzz");
        } else if (bug % 3 == 0) {
            System.out.println("Fizz");
        } else if (bug % 5 == 0) {
            System.out.println("Buzz");
        } else {
            System.out.println(bug);
        }

        StringBuilder primes = new StringBuilder("primes2to50:");
        for (int v = 2; v <= 50; v++) {
            if (isPrime(v)) {
                primes.append(' ').append(v);
            }
        }
        System.out.println(primes.toString());

        System.out.println("Review: pack mutually exclusive rules into one else-if ladder.");
    }
}

